# config_template.py — default settings; copied to config.py by `make`.
#
# Do NOT edit this file for local tuning — edit the generated config.py instead
# (config.py is git-ignored and survives `make clean`). Edit this template only
# to change the project-wide committed defaults.
#
# config.py is imported by Test.py; Test.sh does not read it.

# ── DRAM address mapping ──────────────────────────────────────────────────────
# Name of one profile defined in dram_mapping.py (the committed registry of
# known machines). Add a new machine there, then just point ADDR_PROFILE at it.
ADDR_PROFILE = "arrow_2r"

# ── Machine hardware ──────────────────────────────────────────────────────────
# Not the user-fixed frequency, but the CPU base frequency. e.g. "2.0" / "2.4".
cpu_base_freq = "3.7"     # GHz

dram_bw = "38.4"          # theoretical DRAM bandwidth GB/s. e.g. "23.464" / "44.8"

# If your system spreads a node's CPUs with a stride, set this to 2.
# Check `numactl -H`:  node 0 cpus: 0 1 2 3 ... → 1 ;  0 2 4 6 ... → 2
numa_stride = 1

# Total number of 1G Hugepages available in the node (NOT how many to use).
# Check the grub reservation.
pool_size = 16

# ── Sweep / run knobs ─────────────────────────────────────────────────────────
# True: run repeatedly, increasing cores from min_cores up to NUM_CORES.
# False: run once with the specified number of cores.
sweep_cores = True
min_cores = 3

# Pointer-chasing chains per core, tuned to saturate DRAM bandwidth.
num_chains_per_core = 32

verbose_output = True

chunk_size = 1            # Not used in the current version.

# ── Experiment parameters (formerly Test.sh) ──────────────────────────────────
NUMA_NODE = 0
NUM_CORES = "all"         # "all" or an integer (e.g. 16)
NUM_PAGES = 16            # e.g. 8

ISRECORD = True           # save output to RECORDFILE and append Avg Usage to CSV
RECORDFILE = "results/result.txt"

# Benchmarks to run (passed as a comma-joined list to ./benches).
benchlist = [
    "BW_ALL_HIT_PT_SINGLE",
    "BW_ALL_MISS_PT_SINGLE",
    "BW_ALL_RAND_PC_SINGLE",
    "BW_R0_HIT_PT_SINGLE",
    "BW_R0_MISS_PT_SINGLE",
    "BW_R0_RAND_PC_SINGLE",
]
